  "a80b3729-729e-4bb0-b5d9-844127fff502",  // 06. Orçamento Enviado
  "32677154-b3c1-4482-8d94-63f1ad5a0645",  // 05. AG Orçamento
  "70aaebcf-bed7-41ae-ae7f-186b21f2448c",  // 04. Visita Realizada
  "d09d13f5-a4e2-4928-97e7-60cbb18375c6",  // 03. Visita agendada
  "d7473602-9f4b-4f55-a5c5-9fa663f08c93",  // 02. Qualificação
