];

// ════════════════════════════════════════════════
// LÓGICA (não alterar)
// ════════════════════════════════════════════════
const body = $input.first().json.body ?? $input.first().json;

if (body.eventType !== 'CONTACT_TAG_UPDATE') {
  return [{ json: { skip: true } }];
}

const tagsId    = body.content?.tagsId ?? [];
const contactId = body.content?.id;

if (!contactId) return [{ json: { skip: true } }];

const matched = tagsId.filter(t => STAGE_MAP[t]);
if (matched.length === 0) return [{ json: { skip: true } }];

const winner = STAGE_PRIORITY.find(s => matched.includes(s)) ?? matched[0];
const stage  = STAGE_MAP[winner];

return [{
  json: {
    skip:            false,
    contactId,
    stepId:          stage.stepId,
    dashKey:         stage.dashKey ?? null,
    sendToDash:      stage.dashKey !== null,
    panelId:         PANEL_ID,
    helenToken:      HELENA_TOKEN,
    storeExternalId: STORE_EXTERNAL_ID,
    dashboardUrl:    DASHBOARD_URL,
    webhookSecret:   WEBHOOK_SECRET,
    occurredAt:      body.date,
    eventId:         contactId + '-' + body.date
  }
}];

const ctx  = $('É etapa de funil?').first().json;
const resp = $input.first().json;

let cardId    = null;
let cardFound = false;
let cardRaw   = null;
let agentEmail = null;

try {
  const items = resp.items ?? resp.data ?? [];
  const list  = Array.isArray(items) ? items : [];
  const card  = list[0];
  if (card?.id) {
    cardId    = card.id;
    cardFound = true;
    cardRaw   = card;
    agentEmail = card?.assignedUser?.email ?? card?.agent?.email ?? card?.meta?.assignee?.email ?? null;
  }
} catch(e) {}

return [{ json: { ...ctx, cardId, cardFound, cardRaw, agentEmail } }];
